const MONTHS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

const formatCurrency = (val) => {
  if (val >= 1000000) return `$${(val / 1000000).toFixed(1)}M`;
  if (val >= 1000) return `$${(val / 1000).toFixed(0)}K`;
  return `$${Math.round(val)}`;
};

const generateScenarios = (industry) => {
  const ind = INDUSTRIES[industry];
  const { ly1, ly2, ly3 } = ind.salesHistory;
  const ly1Growth = ((ly1 / ly2) - 1) * 100;
  const ly2Growth = ((ly2 / ly3) - 1) * 100;

  // Brand-specific category trends
  const categoryTrends = industry === "fashion"
    ? [1.10, 0.94, 1.06, 0.99]
    : [1.05, 1.18, 0.96, 1.12];

  // Brand-specific in-season surprises
  const surprises = industry === "fashion"
    ? [
        {
          type: "winner",
          category: ind.categories[0],
          detail: `Your bestselling ${ind.categories[0].toLowerCase()} style has been live for 2 weeks and is selling 40% above its planned weekly velocity. At this pace, you'll be out of stock well before the style's natural end of life. The vendor can produce an additional chase order with a 3-week lead time, but needs a commitment by Friday.`,
          unitsBought: 3000,
          unitsSold: 1134,
          weeklyVelocity: 567,
          plannedVelocity: 405,
          chaseUnits: 2000,
          chaseCost: ind.avgCost * 2000,
          unitPrice: ind.avgPrice,
          chaseLeadTime: 3,
        },
        {
          type: "loser",
          category: ind.categories[2],
          detail: `A fashion dress style launched 2 weeks ago and the initial read is below plan. You have a backup order of 1,000 units arriving next month that you can partially or fully cancel. About 60% of total demand happens in the first 4 weeks, then drops off sharply when the new collection arrives in week 5.`,
          initialBuy: 2000,
          backupOrder: 1000,
          unitsSold: 450,
          weeklyVelocity: 225,
          plannedVelocity: 555,
          cancelCostPerUnit: ind.avgCost,
          unitPrice: ind.avgPrice,
        },
      ]
    : [
        {
          type: "winner",
          detail: "Your Chocolate Peanut Butter Protein (24-pack case) is the #1 seller at Target in 400 doors. Target's buyer wants to expand distribution to all 800 doors in their wellness reset next month. Your current production capacity is 18,000 cases/month. You're shipping 8,000 to Target and 4,000 to DTC and other retail accounts, leaving 6,000 cases of monthly headroom.",
          currentDoors: 400,
          targetDoors: 800,
          casesPerDoorMonth: 20,
          currentVolume: 8000,
          productionCapacity: 18000,
          otherAccountsNeed: 4000,
          casePrice: 37,
          caseCost: 11,
        },
        {
          type: "loser",
          detail: "Your new Mango Ginger Vitamin Gummies launched at GNC 8 weeks ago and are significantly underperforming. You have agreed to take back 1,200 unsold cases. You need to decide where to reallocate this inventory before it ages further (9 months to expiration).",
          takebackCases: 1200,
          channels: [
            { name: "DTC (Website)", velocity: 150, currentWOH: 4, margin: "highest", note: "Strong velocity, low weeks on hand — could absorb inventory quickly. Highest margin channel." },
            { name: "Vitamin Shoppe", velocity: 80, currentWOH: 6, margin: "mid", note: "Moderate velocity, adequate stock levels. Opportunity to expand door count." },
            { name: "Target", velocity: 0, currentWOH: 0, margin: "mid", note: "Product is not currently in Target's assortment. Would require new item setup and slotting fees." },
            { name: "Warehouse (Hold)", velocity: 0, currentWOH: 0, margin: "none", note: "Hold in warehouse for future allocation. Preserves options but inventory continues to age." },
          ],
        },
      ];

  // Brand-specific R5 (promos + markdowns OR rationalization)
  const round4 = industry === "fashion"
    ? {
        promos: [
          { name: "The Spring Fling", category: "Dresses", avgRetail: 128, cost: 56, invDollars: 102400, wos: 5, numStyles: 12, idealDiscount: 20 },
          { name: "Knit Picks Weekend", category: "Tops", avgRetail: 68, cost: 24, invDollars: 34000, wos: 3, numStyles: 8, idealDiscount: 25 },
          { name: "Layer Up Event", category: "Outerwear", avgRetail: 198, cost: 107, invDollars: 69300, wos: 8, numStyles: 6, idealDiscount: 30 },
        ],
        hardMarks: [
          { name: "Floral Midi Dress", originalPrice: 148, cost: 65, unitsBought: 1200, unitsSold: 780, weeksLive: 12, desc: "Age: 12 weeks. Floral print is seasonal — won't carry into fall. Last week's velocity: 35 units.", remainingUnits: 420, idealPrice: 74 },
          { name: "Cropped Linen Blazer", originalPrice: 188, cost: 82, unitsBought: 600, unitsSold: 310, weeksLive: 14, desc: "Age: 14 weeks. Linen is losing relevance as fall approaches. Limited sizes remaining. Last week's velocity: 18 units.", remainingUnits: 290, idealPrice: 85 },
        ],
      }
    : {
        promos: [
          { category: "Protein", avgRetail: 42, cost: 18, invDollars: 185000, wos: 4, numItems: 12, idealDiscount: 20 },
          { category: "Energy Drinks", avgRetail: 32, cost: 11, invDollars: 64000, wos: 3, numItems: 8, idealDiscount: 25 },
          { category: "Vitamins", avgRetail: 28, cost: 7, invDollars: 98000, wos: 9, numItems: 10, idealDiscount: 30 },
        ],
        skuRationalization: [
          { name: "Birthday Cake Protein", category: "Protein", weeklyCases: 45, margin: 68, retailers: 3, catRank: "8 of 12", launched: "8 months ago", note: "Low velocity and ranked near the bottom of the protein lineup. Generates some social media buzz but has not translated into sustained sales.", overlap: "High overlap with Vanilla — 60% of Birthday Cake buyers also buy Vanilla." },
          { name: "Tropical Punch Energy", category: "Energy Drinks", weeklyCases: 30, margin: 65, retailers: 2, catRank: "3 of 8", launched: "6 months ago", note: "Fastest-growing flavor in the category with velocity up 25% month over month. Still ramping — only 6 months old.", overlap: "Low overlap — unique flavor profile attracts a different customer than Berry or Citrus." },
          { name: "Turmeric Ginger Gummies", category: "Vitamins", weeklyCases: 20, margin: 72, retailers: 1, catRank: "10 of 10", launched: "12 months ago", note: "Niche product with loyal repeat buyers but very low volume. Dead last in category ranking. Only carried at Vitamin Shoppe.", overlap: "No overlap — only turmeric product in the lineup. Discontinuing means exiting the functional wellness sub-category." },
          { name: "Oat & Honey Protein Bar", category: "Snacks", weeklyCases: 55, margin: 58, retailers: 4, catRank: "2 of 4", launched: "10 months ago", note: "Second-best performer in Snacks with the widest retail distribution of any snack item. Bar format is growing 15% YoY across the industry.", overlap: "Medium overlap with Peanut Butter Crunch bar — similar customer & snacking occasion." },
        ],
      };

  return {
    round1: {
      ly1Sales: ly1, ly2Sales: ly2, ly3Sales: ly3, ly1Growth, ly2Growth,
      monthlyBase: ly1 / 12,
      categories: ind.categories,
      seasonality: ind.seasonality,
      defaultSpread: ind.defaultSpread,
      bopInventory: ind.bopInventory,
    },
    round2: {
      otbBudget: (() => {
        const ps = ly1 * (1 + ind.growthIdeal / 100);
        const baseEOP = ind.bopInventory * (ps / ly1);
        return ps + baseEOP - ind.bopInventory;
      })(),
      categories: ind.categories,
      categoryTrends,
      lyCatPenetration: ind.assortment.lyCatPenetration,
      trendingPen: (() => {
        const trended = ind.assortment.lyCatPenetration.map((p, i) => p * categoryTrends[i]);
        const total = trended.reduce((a, b) => a + b, 0);
        return trended.map(t => t / total);
      })(),
      lyCatSales: ind.assortment.lyCatPenetration.map(p => p * ly1),
      assortment: ind.assortment,
    },
    round3: { surprises },
    round4,
  };
};


// ---- SHARED COMPONENTS ----

const ProgressBar = ({ current }) => (
  <div style={{ display: "flex", alignItems: "center", gap: 12, width: "100%", justifyContent: "center" }}>
    {[1, 2, 3, 4, 5].map((step) => (
      <div key={step} style={{ display: "flex", alignItems: "center", flex: step < 5 ? 1 : "0 0 auto" }}>
        <div style={{
          width: 32, height: 32, borderRadius: "50%",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 13, fontWeight: 700, fontFamily: "'DM Mono', monospace",
          background: step < current ? "#2d6a4f" : step === current ? "#40916c" : "rgba(255,255,255,0.08)",
          color: step <= current ? "#fff" : "rgba(255,255,255,0.3)",
          border: step === current ? "2px solid #95d5b2" : "2px solid transparent",
          transition: "all 0.4s ease",
          flexShrink: 0,
        }}>
          {step < current ? "✓" : step}
        </div>
        {step < 5 && (
          <div style={{
            flex: 1, height: 2, margin: "0 4px", transition: "all 0.4s ease",
            background: step < current ? "#2d6a4f" : "rgba(255,255,255,0.08)",
          }} />
        )}
      </div>
    ))}
  </div>
);

const KPICard = ({ label, value, subtext, highlight }) => {
  const [pulseKey, setPulseKey] = useState(0);
  const isFirstRender = useRef(true);

  useEffect(() => {
    if (isFirstRender.current) {
      isFirstRender.current = false;
      return;
    }
    setPulseKey((k) => k + 1);
  }, [value]);

  const pulseClass = pulseKey > 0 ? (highlight ? "kpi-pulse-highlight" : "kpi-pulse") : "";

  return (
    <div key={pulseKey} className={pulseClass} style={{
      background: highlight ? "rgba(64,145,108,0.15)" : "rgba(255,255,255,0.04)",
      border: highlight ? "1px solid rgba(64,145,108,0.4)" : "1px solid rgba(255,255,255,0.08)",
      borderRadius: 12, padding: "14px 16px", minWidth: 110, textAlign: "center", flex: "1 1 110px",
    }}>
      <div style={{ fontSize: 11, color: "rgba(255,255,255,0.4)", fontFamily: "'DM Mono', monospace", letterSpacing: 0.5, marginBottom: 4 }}>{label}</div>
      <div style={{ fontSize: 18, fontWeight: 700, color: "#fff", fontFamily: "'Fraunces', serif" }}>{value}</div>
      {subtext && <div style={{ fontSize: 10, color: "rgba(255,255,255,0.4)", marginTop: 2 }}>{subtext}</div>}
    </div>
  );
};

const Button = ({ children, onClick, primary, disabled }) => (
  <button onClick={onClick} disabled={disabled} style={{
    background: disabled ? "rgba(255,255,255,0.05)" : primary ? "#52b788" : "rgba(255,255,255,0.06)",
    color: disabled ? "rgba(255,255,255,0.3)" : primary ? "#0d1b14" : "#fff",
    border: primary ? "none" : "1px solid rgba(255,255,255,0.15)",
    padding: "12px 28px", borderRadius: 8, fontSize: 14, fontWeight: 600,
    fontFamily: "'DM Sans', sans-serif", cursor: disabled ? "not-allowed" : "pointer",
    transition: "all 0.2s ease",
  }}>{children}</button>
);

const SectionLabel = ({ children }) => (
  <div style={{ fontSize: 11, fontFamily: "'DM Mono', monospace", letterSpacing: 1, color: "rgba(255,255,255,0.4)", textTransform: "uppercase", marginBottom: 12 }}>{children}</div>
);

const InfoTooltip = ({ text }) => {
  const [show, setShow] = useState(false);
  return (
    <span style={{ position: "relative", display: "inline-block", marginLeft: 6 }}>
      <span onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)} onClick={() => setShow(!show)} style={{
        display: "inline-flex", alignItems: "center", justifyContent: "center",
        width: 14, height: 14, borderRadius: "50%", background: "rgba(149,213,178,0.2)",
        color: "#95d5b2", fontSize: 9, fontWeight: 700, cursor: "help",
        fontFamily: "'DM Mono', monospace",
      }}>i</span>
      {show && (
        <span style={{
          position: "absolute", bottom: "100%", left: "50%", transform: "translateX(-50%)",
          background: "rgba(0,0,0,0.95)", color: "#fff", padding: "10px 14px", borderRadius: 6,
          fontSize: 11, lineHeight: 1.5, width: 240, whiteSpace: "normal", zIndex: 100,
          marginBottom: 6, border: "1px solid rgba(149,213,178,0.3)", fontWeight: 400, textAlign: "left",
        }}>{text}</span>
      )}
    </span>
  );
};

const SliderInput = ({ label, value, onChange, min, max, step = 1, format, hint }) => (
  <div style={{ marginBottom: 16 }}>
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 8 }}>
      <label style={{ fontSize: 13, color: "rgba(255,255,255,0.7)", fontWeight: 500 }}>{label}</label>
      <span style={{ fontSize: 16, fontWeight: 700, color: "#b7e4c7", fontFamily: "'DM Mono', monospace" }}>{format ? format(value) : value}</span>
    </div>
    <input className="pulse-slider" type="range" min={min} max={max} step={step} value={value} onChange={(e) => onChange(Number(e.target.value))} style={{ width: "100%", accentColor: "#52b788", cursor: "pointer" }} />
    {hint && <div style={{ fontSize: 11, color: "rgba(255,255,255,0.35)", marginTop: 4, fontFamily: "'DM Mono', monospace" }}>{hint}</div>}
  </div>
);


