// ---- CONFETTI HELPER ----

let confettiPromise = null;
const loadConfetti = () => {
  if (confettiPromise) return confettiPromise;
  confettiPromise = new Promise((resolve, reject) => {
    if (typeof window !== "undefined" && window.confetti) {
      resolve(window.confetti);
      return;
    }
    const script = document.createElement("script");
    script.src = "https://cdn.jsdelivr.net/npm/canvas-confetti@1.9.3/dist/confetti.browser.min.js";
    script.async = true;
    script.onload = () => resolve(window.confetti);
    script.onerror = reject;
    document.head.appendChild(script);
  });
  return confettiPromise;
};

const fireConfetti = async (intensity = "small") => {
  try {
    const confetti = await loadConfetti();
    if (!confetti) return;
    if (intensity === "small") {
      // Modest burst from center for round-level rewards
      confetti({
        particleCount: 60,
        spread: 70,
        origin: { y: 0.4 },
        colors: ["#95d5b2", "#52b788", "#b7e4c7", "#e9c46a"],
        startVelocity: 35,
        gravity: 1,
        scalar: 0.9,
      });
    } else {
      // Big celebration for the final scorecard — two side cannons
      const duration = 2500;
      const end = Date.now() + duration;
      const colors = ["#95d5b2", "#52b788", "#b7e4c7", "#e9c46a", "#f4a261"];
      (function frame() {
        confetti({
          particleCount: 4,
          angle: 60,
          spread: 55,
          origin: { x: 0, y: 0.6 },
          colors,
        });
        confetti({
          particleCount: 4,
          angle: 120,
          spread: 55,
          origin: { x: 1, y: 0.6 },
          colors,
        });
        if (Date.now() < end) requestAnimationFrame(frame);
      })();
    }
  } catch (e) {
    // Silent fail — confetti is non-critical
  }
};


// ---- SHARE IMAGE GENERATOR ----

const generateShareImage = ({ score, grade, earnedTitle, gradeColor }) => {
  const canvas = document.createElement("canvas");
  canvas.width = 1200;
  canvas.height = 630;
  const ctx = canvas.getContext("2d");

  // Background gradient matching game aesthetic
  const bg = ctx.createLinearGradient(0, 0, 1200, 630);
  bg.addColorStop(0, "#0d1b14");
  bg.addColorStop(0.5, "#1a2e23");
  bg.addColorStop(1, "#0d1b14");
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, 1200, 630);

  // Subtle dot pattern overlay
  ctx.fillStyle = "rgba(149, 213, 178, 0.04)";
  for (let x = 24; x < 1200; x += 32) {
    for (let y = 24; y < 630; y += 32) {
      ctx.beginPath();
      ctx.arc(x, y, 1.5, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  // Top label — "THE PLANNING LAB"
  ctx.fillStyle = "rgba(149, 213, 178, 0.7)";
  ctx.font = "600 24px 'DM Mono', monospace";
  ctx.textAlign = "center";
  ctx.fillText("THE PLANNING LAB", 600, 85);

  // Subtitle
  ctx.fillStyle = "rgba(149, 213, 178, 0.45)";
  ctx.font = "500 16px 'DM Mono', monospace";
  ctx.fillText("A MERCHANDISE PLANNING SIMULATOR", 600, 118);

  // Grade circle — larger, positioned left
  const circleX = 330;
  const circleY = 340;
  const outerRadius = 150;
  const innerRadius = 118;

  // Outer ring
  ctx.beginPath();
  ctx.arc(circleX, circleY, outerRadius, 0, Math.PI * 2);
  ctx.fillStyle = "rgba(255, 255, 255, 0.06)";
  ctx.fill();

  // Score arc
  ctx.beginPath();
  ctx.moveTo(circleX, circleY);
  ctx.arc(circleX, circleY, outerRadius, -Math.PI / 2, -Math.PI / 2 + (score / 100) * Math.PI * 2);
  ctx.closePath();
  ctx.fillStyle = gradeColor;
  ctx.fill();

  // Inner circle
  ctx.beginPath();
  ctx.arc(circleX, circleY, innerRadius, 0, Math.PI * 2);
  ctx.fillStyle = "#0d1b14";
  ctx.fill();

  // Grade letter
  ctx.fillStyle = gradeColor;
  ctx.font = "800 128px 'Fraunces', Georgia, serif";
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(grade, circleX, circleY - 10);

  // Score number under grade
  ctx.fillStyle = "rgba(255, 255, 255, 0.55)";
  ctx.font = "500 24px 'DM Mono', monospace";
  ctx.fillText(`${score}/100`, circleX, circleY + 60);

  // Right side — earned title block
  ctx.textBaseline = "alphabetic";
  ctx.textAlign = "left";

  // "I EARNED THE TITLE OF" label
  ctx.fillStyle = "rgba(149, 213, 178, 0.55)";
  ctx.font = "500 18px 'DM Mono', monospace";
  ctx.fillText("I EARNED THE TITLE OF", 520, 270);

  // Title — large serif
  ctx.fillStyle = "#ffffff";
  ctx.font = "700 64px 'Fraunces', Georgia, serif";
  ctx.fillText(earnedTitle, 520, 345);

  // Accent line under title
  ctx.strokeStyle = gradeColor;
  ctx.lineWidth = 4;
  ctx.beginPath();
  ctx.moveTo(520, 375);
  ctx.lineTo(660, 375);
  ctx.stroke();

  // Challenge text
  ctx.fillStyle = "rgba(255, 255, 255, 0.65)";
  ctx.font = "400 26px 'DM Sans', sans-serif";
  ctx.fillText("Think you can beat me?", 520, 430);

  // Footer signature
  ctx.fillStyle = "rgba(149, 213, 178, 0.45)";
  ctx.font = "500 15px 'DM Mono', monospace";
  ctx.textAlign = "center";
  ctx.fillText("BUILT BY CALLIE SHEPARD", 600, 575);

  return canvas.toDataURL("image/png");
};


